/**
 * MedX responsive layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Breakpoint-driven layout switching.
 */
const RESPONSIVE_TOKENS = Object.freeze({
  primary: { value: "layout-responsive-primary", scope: "layout" },
  secondary: { value: "layout-responsive-secondary", scope: "layout" },
  muted: { value: "layout-responsive-muted", scope: "layout" },
  accent: { value: "layout-responsive-accent", scope: "layout" },
  surface: { value: "layout-responsive-surface", scope: "layout" },
});

const RESPONSIVE_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const RESPONSIVE_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const responsiveRegistry = new Map();
const RESPONSIVE_listeners = new Set();
let RESPONSIVE_seq = 0;

function createResponsiveId(prefix = "medx-layout-responsive") {
  RESPONSIVE_seq += 1;
  return `${prefix}-${RESPONSIVE_seq}`;
}

function registerResponsive(config = {}) {
  const entryId = config.id ?? createResponsiveId();
  const preset = RESPONSIVE_PRESETS[config.preset ?? "default"] ?? RESPONSIVE_PRESETS.default;
  const token = RESPONSIVE_TOKENS[config.token ?? preset.token] ?? RESPONSIVE_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: RESPONSIVE_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  responsiveRegistry.set(entryId, entry);
  notifyResponsiveListeners("register", entry);
  return entry;
}

function updateResponsive(id, patch = {}) {
  const entry = responsiveRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyResponsiveListeners("update", entry);
  return entry;
}

function resolveResponsive(id) {
  const entry = responsiveRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listResponsiveEntries(filter = {}) {
  let items = Array.from(responsiveRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onResponsiveEvent(listener) {
  RESPONSIVE_listeners.add(listener);
  return () => RESPONSIVE_listeners.delete(listener);
}

function notifyResponsiveListeners(type, entry) {
  for (const listener of RESPONSIVE_listeners) {
    try {
      listener({ type, entry, registrySize: responsiveRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:responsive] listener error", err.message);
    }
  }
}

function getResponsiveMetrics() {
  const items = listResponsiveEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(RESPONSIVE_TOKENS).length,
    presets: Object.keys(RESPONSIVE_PRESETS).length,
  };
}

async function runMedxResponsive() {
  console.log("[medx:ui:layout:responsive] runtime initialized");
  console.log(`[medx:ui:layout:responsive] tokens=${Object.keys(RESPONSIVE_TOKENS).length} presets=${Object.keys(RESPONSIVE_PRESETS).length}`);

  const events = [];
  onResponsiveEvent((e) => events.push(e.type));

  const domains = Object.keys(RESPONSIVE_SUPPLY_CHAIN);
  const presets = Object.keys(RESPONSIVE_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerResponsive({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/responsive" },
    });
  }

  const first = listResponsiveEntries()[0];
  if (first) updateResponsive(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getResponsiveMetrics();
  const resolved = first ? resolveResponsive(first.id) : null;

  console.log(`[medx:ui:layout:responsive] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:responsive] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:responsive] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:responsive] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:responsive] bootstrap complete");
}

module.exports = runMedxResponsive;
